def apply_product_filters(query, f: t.Optional[ProductFilterInput]):
    if not f:
        return query
    if f.ids:
        query = query.filter(Product.id.in_([int(x) for x in f.ids]))
    if f.seller_ids:
        query = query.filter(Product.seller_id.in_([int(x) for x in f.seller_ids]))
    if f.category_slugs:
        query = query.join(Product.categories).filter(Category.slug.in_(f.category_slugs))
    if f.min_price is not None:
        query = query.filter(Product.price >= f.min_price)
    if f.max_price is not None:
        query = query.filter(Product.price <= f.max_price)
    if f.search:
        like = f"%{f.search}%"
        query = query.filter((Product.name.ilike(like)) | (Product.sku.ilike(like)) | (Product.description.ilike(like)))
    return query


