@strawberry.type
class Mutation:
    @strawberry.mutation
    def create_seller(self, info, data: SellerInput) -> SellerType:
        db: Session = info.context["db"]
        s = Seller(name=data.name, website=data.website)
        db.add(s)
        db.commit()
        db.refresh(s)
        return s

    @strawberry.mutation
    def create_category(self, info, data: CategoryInput) -> CategoryType:
        db: Session = info.context["db"]
        c = Category(name=data.name, slug=data.slug)
        db.add(c)
        db.commit()
        db.refresh(c)
        return c

    @strawberry.mutation
    def create_product(self, info, data: ProductInput) -> ProductType:
        db: Session = info.context["db"]
        p = Product(
            sku=data.sku,
            name=data.name,
            description=data.description,
            price=data.price,
            currency=data.currency,
            seller_id=int(data.seller_id) if data.seller_id is not None else None,
        )

        if data.category_ids:
            cats = db.query(Category).filter(Category.id.in_([int(x) for x in data.category_ids])).all()
            p.categories = cats

        if data.image_urls:
            p.images = [ProductImage(url=i.url, alt_text=i.alt_text, sort_order=i.sort_order) for i in data.image_urls]

        db.add(p)
        db.commit()
        db.refresh(p)
        p = (
            db.query(Product)
            .options(
                selectinload(Product.seller),
                selectinload(Product.categories),
                selectinload(Product.images),
                selectinload(Product.reviews),
            )
            .filter(Product.id == p.id)
            .one()
        )
        return p

    @strawberry.mutation
    def add_review(self, info, product_id: strawberry.ID, data: ReviewInput) -> ReviewType:
        db: Session = info.context["db"]
        r = Review(
            product_id=int(product_id),
            author=data.author,
            rating=int(data.rating),
            title=data.title,
            body=data.body,
        )
        db.add(r)
        db.commit()
        db.refresh(r)
        return r


